import { useState, createContext } from 'react'
import axios from 'axios'
import { useNavigate } from 'react-router-dom'


const BookContext = createContext()

const BookProvider = ({children}) => {

    const [search, setSearch] = useState({
        query: ''
    })

    const navigate = useNavigate();

    const [loading, setLoading] = useState(false)
    const [bookData, setBookData] = useState([])

    const getBookList = async datos => {
       
        setLoading(true)

        if(search.query !== '')
        {
            try{
                const url = "https://www.googleapis.com/books/v1/volumes?q=" + search.query + "&key=" + process.env.REACT_APP_GOOGLE_BOOKS_API_KEY + "&maxResults=40&printType=books"
    
                const { data: res } = await axios(url)
    
                setBookData(res.items)
            
            }
            catch{
                console.log()
            }
            finally{
                setLoading(false)
            }

            navigate("list", { replace: true });
        }
        else
        {
            navigate("/", { replace: true });
        }

            
        
    }
    

    const [userBooks, setUserBooks] = useState([])

    const [userSearched, setUserSearched] = useState([])



    return (
        <BookContext.Provider value={{ getBookList, bookData, search, setSearch, loading, setLoading, userBooks, setUserBooks, userSearched, setUserSearched }}>
            {children}
        </BookContext.Provider>
    )
}

export { BookProvider }

export default BookContext
